from django.contrib.auth.models import User
from django.contrib.sessions.models import Session
from saml2.auth import Saml2Auth
from saml2.xmlparser import parse_xml_doc

# Initialize SAML authentication
auth = Saml2Auth()

# Handle SAML POST response
def saml_post_handler(request):
    # Parse SAML XML response
    xml_doc = parse_xml_doc(request.body.decode('utf-8'))

    # Validate XML structure
    if not xml_doc.validate():
        return HttpResponseBadRequest('Invalid SAML XML response.')

    # Extract user information from assertion attributes
    name_id = xml_doc.find('saml:NameID').text
    attributes = {attr.get('Name'): attr.text for attr in xml_doc.findall('saml:Attribute')}

    # Create Django user session
    user, _ = User.objects.get_or_create(username=name_id)
    session = Session.objects.create(
        session_key=name_id,
        expire_date=datetime.now() + timedelta(minutes=30)
    )
    request.session = session._session

    # Set user attributes
    for key, value in attributes.items():
        setattr(user, key, value)

    # Login user
    login(request, user)

    # Redirect to enterprise portal home page
    return redirect('home')